private long toIndex(long... transposedIndex) {
    long b = 0;
    int bIndex = length - 1;
    long mask = 1L << (bits - 1);
    for (int i = 0; i < bits; i++) {
        for (int j = 0; j < transposedIndex.length; j++) {
            if ((transposedIndex[j] & mask) != 0) {
                b |= 1L << bIndex;
            }
            bIndex--;
        }
        mask >>= 1;
    }
    // b is expected to be BigEndian
    return b;
}

